#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""deploy_linefix.py — Phase 3.3 修复 LineItem 缺字段 AttributeError (500 根因)

根因: data/models.py 的 LineItem 用 extra="allow", 只显式声明 4 个字段。
      海外抓取部分失败时, 某财报字段未取到 → 该属性整个不存在 →
      任何 agent 裸访问 item.net_income / item.revenue 等 → AttributeError →
      warren_buffett 等崩溃 → /api/analyze 返回 500。
      (之前 current_price=0 在最前面短路, 这个雷够不着; 数据层一修就暴露。)

修复: LineItem 补全 18 个 agent 会访问的财报字段为 Optional=None。
      缺字段时返回 None(agent 本就 handle None), 不再 AttributeError。
      已对全部 agent grep 字段集 + 真实 warren_buffett 分析函数沙箱跑通验证。

用法: poetry run python deploy_linefix.py   (项目根目录)
回滚: deploy_backup/<时间戳>/ 覆盖回去
"""
import base64, os, sys, shutil
from datetime import datetime

B64 = ""
REL = "src/data/models.py"

def main():
    root = os.getcwd()
    if not os.path.isdir(os.path.join(root, "src")):
        print("[FAIL] 请在项目根目录(含 src/)运行"); sys.exit(1)
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bdir = os.path.join(root, "deploy_backup", ts); os.makedirs(bdir, exist_ok=True)
    dst = os.path.join(root, *REL.split("/"))
    if os.path.exists(dst):
        shutil.copy2(dst, os.path.join(bdir, REL.replace("/", "__")))
    with open(dst, "wb") as f:
        f.write(base64.b64decode(B64))
    print(f"[OK] 写入 {REL}")
    print(f"[OK] 备份 -> deploy_backup/{ts}/")
    n = 0
    for r,_,_ in os.walk(os.path.join(root,"src")):
        if r.endswith("__pycache__"): shutil.rmtree(r, ignore_errors=True); n+=1
    print(f"[OK] 清理 {n} 个 __pycache__")
    # 验证: 构造缺字段 LineItem, 18 字段全返回 None
    sys.path.insert(0, root)
    for m in [m for m in sys.modules if "data.models" in m]: del sys.modules[m]
    from src.data.models import LineItem
    li = LineItem(ticker="600519.SH", report_period="2025-12-31", period="ttm", currency="CNY")
    fields = ["revenue","net_income","operating_income","gross_profit","free_cash_flow",
        "capital_expenditure","depreciation_and_amortization","operating_expense",
        "research_and_development","total_assets","total_liabilities","current_assets",
        "current_liabilities","cash_and_equivalents","shareholders_equity",
        "outstanding_shares","goodwill_and_intangible_assets",
        "dividends_and_other_cash_distributions"]
    for f in fields:
        assert getattr(li, f) is None, f"{f} 应为 None"
    print(f"  [PASS] 缺字段 LineItem 访问 {len(fields)} 字段 -> None, 无 AttributeError")
    print("-"*60)
    print("[SUCCESS] LineItem 修复部署完成 — 重启 web_app 重跑, /api/analyze 不再 500")

if __name__ == "__main__":
    main()
